const input = $input.first().json;
const filePath = input.file_path;
const targetFolderId = input.target_folder_id;

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const community = 'YOUR_COMMUNITY';
const room = 'YOUR_ROOM';
const apiBase = 'https://api.interaxo.se';

const fileName = filePath.split('/').pop();
const namn = fileName.replace(/\.ifc$/i, '');

const staticData = $getWorkflowStaticData('global');
if (!staticData.uploads) staticData.uploads = {};
const prev = staticData.uploads[filePath];

if (prev && (Date.now() - new Date(prev.last_upload).getTime()) < 30000) {
  return [{ json: { skip: true, reason: 'Uploaded less than 30s ago', file_name: fileName } }];
}

const tokenBody = [
  'grant_type=client_credentials',
  'client_id=' + encodeURIComponent(clientId),
  'client_secret=' + encodeURIComponent(clientSecret),
  'audience=' + encodeURIComponent('https://api.interaxo.com/v1/')
].join('&');

const tokenRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://login.collaboration-sso.com/oauth/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: tokenBody,
  json: true
});
const token = tokenRes.access_token;

const entries = await this.helpers.httpRequest({
  method: 'GET',
  url: `${apiBase}/v1/${community}/rooms/${room}/content/${targetFolderId}/children?limit=500`,
  headers: {
    'Authorization': `Bearer ${token}`,
    'X-Requested-With': 'XMLHttpRequest'
  },
  json: true
});

const matchingEntry = (Array.isArray(entries) ? entries : []).find(e => {
  const namnField = (e.fields || []).find(f => f.name === 'NAMN');
  return namnField && namnField.value === namn;
});

if (!matchingEntry) {
  return [{ json: { skip: true, reason: 'No matching entry for NAMN: ' + namn, file_name: fileName } }];
}

let existingFileId = prev?.interaxo_file_id || null;
let action = 'create';

if (matchingEntry.child_count > 0 || existingFileId) {
  if (!existingFileId) {
    const children = await this.helpers.httpRequest({
      method: 'GET',
      url: `${apiBase}/v1/${community}/rooms/${room}/content/${matchingEntry.id}/children`,
      headers: {
        'Authorization': `Bearer ${token}`,
        'X-Requested-With': 'XMLHttpRequest'
      },
      json: true
    });
    const existing = (Array.isArray(children) ? children : []).find(c => c.type === 'file');
    if (existing) existingFileId = existing.id;
  }
  if (existingFileId) action = 'update';
}

let uploadUrl;
if (action === 'update') {
  uploadUrl = `${apiBase}/v1/${community}/rooms/${room}/files/${existingFileId}/versions`;
} else {
  uploadUrl = `${apiBase}/v1/${community}/rooms/${room}/content/${matchingEntry.id}/children`;
}

return [{ json: {
  skip: false,
  token,
  entry_id: matchingEntry.id,
  file_id: existingFileId,
  action,
  upload_url: uploadUrl,
  file_path: filePath,
  file_name: fileName,
  namn
} }];

const input = $input.first().json;
const prepData = $('Prepare Upload').item.json;

const staticData = $getWorkflowStaticData('global');
if (!staticData.uploads) staticData.uploads = {};

staticData.uploads[prepData.file_path] = {
  interaxo_file_id: input.id || prepData.file_id,
  entry_id: prepData.entry_id,
  last_upload: new Date().toISOString()
};

return [{ json: {
  success: true,
  fileName: prepData.file_name,
  namn: prepData.namn,
  action: prepData.action,
  entryId: prepData.entry_id,
  fileId: input.id || prepData.file_id,
  version: input.version || null
} }];
